vec4 composite( vec4 a, vec4 b) {
    return a * (1. - b.a) + b;
}



    mat2 rot2(float a) {
        float c = cos(a);
        float s = sin(a);
        return mat2(c, -s, s, c);
    }

    vec2 l2s( vec2 v ) {
        return (vec4(v,0.,1.)*acLayerToScreen).xy;
    }

    vec4 composite( vec4 a, vec4 b) {
        return a * (1. - b.a) + b;
    }

    void main() {

        vec2 st = acLayerNorm;
        st -= offset/500.*vec2(1.,-1.);
        st -= 0.5;
        st.x *= acLayerSize.x/acLayerSize.y;
        st *= rot2( -angle * 0.0174533 );
        st /= scale;
        st.x /= acLayerSize.x/acLayerSize.y;
        st += 0.5;

        vec2 sampleCoord = l2s(st);
        if( sample == 0 ) {
            sampleCoord *= acScreenSize;
            sampleCoord = floor(sampleCoord) + 0.5;
            sampleCoord /= acScreenSize;
        }

        vec4 scaledTexColor = texture2DCv(inputImg.texture,sampleCoord);
        if( maskToLayer ) {
            vec4 baseColor = texture2DCv(inputImg.texture,acScreenNorm);
            gl_FragColor = composite(baseColor*fill, scaledTexColor*baseColor.a*alpha);
        } else if( fill > 0.0001 ) {
            vec4 baseColor = texture2DCv(inputImg.texture,acScreenNorm);
            gl_FragColor = composite(baseColor*fill, scaledTexColor*alpha);
        } else {
            gl_FragColor = scaledTexColor * alpha;
        }

    }
